import{_ as i,o as a,c as e,ai as l}from"./chunks/framework.ampVZV4B.js";const k=JSON.parse('{"title":"本地 MySQL 安装配置（Windows）","description":"","frontmatter":{},"headers":[],"relativePath":"devtools/mysql-local.md","filePath":"devtools/mysql-local.md"}'),n={name:"devtools/mysql-local.md"};function r(t,s,d,h,o,p){return a(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="本地-mysql-安装配置-windows" tabindex="-1">本地 MySQL 安装配置（Windows） <a class="header-anchor" href="#本地-mysql-安装配置-windows" aria-label="Permalink to “本地 MySQL 安装配置（Windows）”">​</a></h1><h2 id="下载安装" tabindex="-1">下载安装 <a class="header-anchor" href="#下载安装" aria-label="Permalink to “下载安装”">​</a></h2><ul><li>下载地址：<a href="https://dev.mysql.com/downloads/installer/" target="_blank" rel="noreferrer">https://dev.mysql.com/downloads/installer/</a></li><li>推荐：<code>MySQL Installer Community</code></li></ul><h2 id="安装步骤-最简" tabindex="-1">安装步骤（最简） <a class="header-anchor" href="#安装步骤-最简" aria-label="Permalink to “安装步骤（最简）”">​</a></h2><ol><li>选择 <code>Server only</code>（只装服务端）或 <code>Developer Default</code>（开发全套）。</li><li>保留默认端口 <code>3306</code>。</li><li>设置 <code>root</code> 密码并记住。</li><li>完成安装后，确认服务 <code>MySQL80</code> 已启动。</li></ol><h2 id="核心配置" tabindex="-1">核心配置 <a class="header-anchor" href="#核心配置" aria-label="Permalink to “核心配置”">​</a></h2><ul><li>配置文件常见路径：<code>C:\\ProgramData\\MySQL\\MySQL Server 8.0\\my.ini</code></li><li>常用项（按需）：</li></ul><div class="language-ini line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[mysqld]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=3306</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">character-set-server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=utf8mb4</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">collation-server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=utf8mb4_general_ci</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>修改后重启 MySQL 服务生效。</p><h2 id="初始化与验证" tabindex="-1">初始化与验证 <a class="header-anchor" href="#初始化与验证" aria-label="Permalink to “初始化与验证”">​</a></h2><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> DATABASE</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> demo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> CHARACTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> SET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> utf8mb4 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COLLATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> utf8mb4_general_ci;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW DATABASES;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> VERSION</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="常见问题-快速处理" tabindex="-1">常见问题（快速处理） <a class="header-anchor" href="#常见问题-快速处理" aria-label="Permalink to “常见问题（快速处理）”">​</a></h2><ul><li>端口占用：改 <code>my.ini</code> 的 <code>port</code>，或释放 <code>3306</code> 占用进程。</li><li>无法连接：确认 <code>MySQL80</code> 服务在运行、账号密码正确、主机是 <code>127.0.0.1</code>。</li><li>中文乱码：确认库/表/连接都用 <code>utf8mb4</code>。</li></ul>`,13)])])}const m=i(n,[["render",r]]);export{k as __pageData,m as default};
